\For{$i = 1 \ldots \ln(n)$}{
    Sample $u,v$ from $V$ uniformly\;
    Compute $Est$ on $\{u,v\} \times V$\;
    Compute $Int(u,v)$\;
    \If{$|Int(u,v)| \geq \frac{n}{2}$}{
        Compute $Int'(u,v)$\;
        \For{$w \in Int'(u,v)$}{
            $Emb(w) = Est(u,w)$\;
        }
        $x_u, x_v \leftarrow$ middle vertices of $Int'(u,v)$\;
        \For{$w \notin Int'(u,v)$}{
            \If{$Est(x_u,w) > Est(x_v,w)$}{
                $Emb(w) = Emb(x_u) + Est(x_u,w)$\;
            }
            \If{$Est(x_u,w) < Est(x_v,w)$}{
                $Emb(w) = Emb(x_u) - Est(x_u,w)$\;
            }
        }
        \Return $Emb$\;
    }
}
\Return FALSE
\end{algorithm}

