\begin{algorithm}[H]
\caption{Signal Proportion Estimator}
\KwIn{$p$-values of the observed test statistics and bounding sequences $c_{m,0.5}$ and $c_{m,1}$}
\KwOut{a proportion estimate $\hat{\pi}$}
Rank the variables by their $p$-values so that $p_{(1)} < p_{(2)} < \ldots < p_{(m)}$\;
Compute
\[\hat{\pi}_{0.5} = \max_{1\leq j\leq m}\frac{j/m-p_{(j)}-c_{m,0.5}\cdot\sqrt{p_{(j)}}}{1-p_{(j)}} \quad\text{and}\quad \hat{\pi}_1 = \max_{1\leq j\leq m}\frac{j/m-p_{(j)}-c_{m,1}\cdot p_{(j)}}{1-p_{(j)}}\]
Obtain $\hat{\pi} = \max\{\hat{\pi}_{0.5},\hat{\pi}_1\}$
\end{algorithm}

