\SetAlgoLined
\KwIn{Classifiers $h_0^*$ and $h_1^*$}
\KwOut{A randomized classifier $h_{\text{Fair}}^*: \mathcal{X} \times \{0,1\} \to \{0,1\}$}
Compute $\alpha = \mathbb{P}_{\mu_0^*}(h_0^*(X)=1)$ and $\beta = \mathbb{P}_{\mu_1^*}(h_1^*(X)=1)$. W.L.O.G. assume $\alpha \geq \beta$\;
For $(x,a)$, randomly sample $s$ from the uniform distribution $U(0,1)$\;
Construct $h_{\text{Fair}}^*$ as follows:
\[
h_{\text{Fair}}^*(x,a) := \begin{cases}
a = 0: \begin{cases}
0 & \text{if } h_0^*(x)=0 \text{ or } h_0^*(x)=1 \text{ and } s > \frac{\alpha+\beta}{2\alpha}\\
1 & \text{if } h_0^*(x)=1 \text{ and } s \leq \frac{\alpha+\beta}{2\alpha}
\end{cases}\\
a = 1: \begin{cases}
0 & \text{if } h_1^*(x)=0 \text{ and } s > \frac{\alpha-\beta}{2(1-\beta)}\\
1 & \text{if } h_1^*(x)=1 \text{ or } h_1^*(x)=0 \text{ and } s \leq \frac{\alpha-\beta}{2(1-\beta)}
\end{cases}
\end{cases}
\]
\Return{$h_{\text{Fair}}^*$}
\end{algorithm}

