\begin{algorithm}[H]
\caption{Basic elastic formulation slice division process (negative balancing needs)}
\SetAlgoLined
\textit{Initialization of the set of time steps}\\
$T_{div} \leftarrow t \in T_m \mid bn_t < 0$\\
\textit{Initialization of the first slice i = 1}\\
$V_1 \leftarrow \max(-V^s, \max_{t\in T_{div}} bn_t)$\\
\textit{Recursion}\\
\For{$i > 1$}{
    \While{$\sum_{1\leq j<i} (V_j) > \min_{t\in T_{div}} bn_t$}{
        $V_i \leftarrow \max(-V^s, \max_{t\in T_{div}}(bn_t - \sum_{1\leq j<i} (V_j)))$ \triangleright Compute the maximum size of $V_i$\\
        \For{$t \in T_{div}$}{
            $qt_{,i} \leftarrow |V_i|$ \triangleright Extract the order quantity for relevant time steps\\
            $\sigma_{t,i} \leftarrow 1$ \triangleright Set the order direction\\
            \If{$bn_t - \sum_{1\leq j\leq i} (V_j) = 0$}{
                $T_{div} \leftarrow T_{div} - \{t\}$ \triangleright Remove now ``empty'' time steps from $T_{div}$
            }
        }
        $i \leftarrow i + 1$
    }
}
\end{algorithm}

