\State \textbf{Input:} Independent initial samples $x_1^{(0)},...,x_N^{(0)}$ from $\mu_0$, momentum parameters $m_l\in[0,1)$ for $l=1,...,L$.
\State Initialize $(v_1,...,v_N)=0$.
\For{$l=1,...,L$}
\State - Set $(\tilde x_1^{(0)},...,\tilde x_N^{(0)})=(x_1^{(l-1)},...,x_N^{(l-1)})$.
\State - Simulate $T_l$ steps of the (momentum) MMD flow:
\For{$t=1,...,T_l$}
\State - Update $v$ by
\begin{align*}
(v_1,...,v_N)\leftarrow \nabla F_d(\tilde x_1^{(t-1)},...,\tilde x_N^{(t-1)}|y_1,...,y_M)+m_l (v_1,...,v_N)
\end{align*}
\State - Update the flow samples:
\begin{align*}
(\tilde x_1^{(t)},...,\tilde x_N^{(t)})=(\tilde x_1^{(t-1)},...,\tilde x_N^{(t-1)})-\tau N\ (v_1,...,v_N)
\end{align*}
\EndFor
\State - Train $\Phi_l$ such that $\tilde x^{(T_l)}\approx \tilde x_i^{(0)}-\Phi_l(\tilde x_i^{(0)}) $ by minimizing the loss
\begin{align*}
\mathcal L(\theta_l)=\frac1N\sum_{i=1}^N \|\Phi_l(\tilde x_i^{(0)})-(\tilde x_i^{(0)}-\tilde x_i^{(T_l)})\|^2.
\end{align*}
\State - Set $(x_1^{(l)},...,x_N^{(l)})=(x_1^{(l-1)},...,x_N^{(l-1)})-(\Phi_l(x_1^{(l-1)}),...,\Phi_l(x_N^{(l-1)}))$.
\EndFor
\end{algorithmic}

