\caption{Bounding sequence $c_{m,\delta}$}
\KwIn{$N$ sets of $p$-values generated by the joint null distribution of $\{z_1,\ldots z_m\}$}
\KwOut{bounding sequences $c_{m,0.5}$ and $c_{m,1}$}
\For{$a = 1,2\ldots,N$}{
Rank the $a$-th set of p-values such that $p_{a,(1)} < p_{a,(2)} < \cdots < p_{a,(m)}$\;
Compute
\[
V_{a,0.5} = \max_{1\leq j\leq m} \frac{|j/m - p_{a,(j)}|}{\sqrt{p_{a,(j)}}} \quad\text{and}\quad V_{a,1} = \max_{1\leq j\leq m} \frac{|j/m - p_{a,(j)}|}{p_{a,(j)}}
\]
}
Compute $c_{m,0.5}$ as the $(1-1/\sqrt{\log m})$-th quantile of the empirical distribution of $V_{a,0.5}, a=1,\ldots N$ and compute $c_{m,1}$ as the $(1-1/\sqrt{\log m})$-th quantile of the empirical distribution of $V_{a,1}, a=1,\ldots N$.
