\State $Z_{t:\mathbf{T}}, W_{t:\mathbf{T}} \gets \text{OPT}([Y_t\ \hat{Y}_{t+1:\mathbf{T}}], P_t, C_t, \mathcal{T})$ \Comment{Run Optimization Policy}
\State $P_{t+1} \gets P_t + Z_t$ \Comment{Execute trades at current timestep}
\State $C_{t+1} \gets C_t - Y_t\cdot Z_t - F\Vec{1} \cdot W_t$ \Comment{Calculate cash}
\State $Y_{t+1} \gets \text{MarketObserver}()$ \Comment{Observe the market for new price information}
\State $t \gets t + 1$
\EndWhile
\Ensure $P_\mathbf{T} \geq \mathcal{T}$
\end{algorithmic}
