\begin{algorithm}[H]
\caption{Randomized $r$-sets-Douglas-Rachford (RrDR) method}
\Require{$A \in \mathbb{R}^{m\times n}$, $b \in \mathbb{R}^m$, $r \in \mathbb{Z}_+$, $k=0$, extrapolation/relaxation parameter $\alpha \in (0,1)$ and an initial $x^0 \in \mathbb{R}^n$.}
\begin{algorithmic}[1]
\State Set $z_0^k := x^k$.
\For{$\ell = 1,\ldots,r$}
\State Select $j_{k_\ell} \in \{1,\ldots,m\}$ with probability $\Pr(\text{row} = j_{k_\ell}) = \frac{\|a_{j_{k_\ell}}\|_2^2}{\|A\|_F^2}$.
\State Compute
\[z_\ell^k := z_{\ell-1}^k - 2\frac{\langle a_{j_{k_\ell}}, z_{\ell-1}^k \rangle - b_{j_{k_\ell}}}{\|a_{j_{k_\ell}}\|_2^2}a_{j_{k_\ell}}.\]
\EndFor
\State Update
\[x^{k+1} := (1-\alpha)x^k + \alpha z_r^k.\]
\State If the stopping rule is satisfied, stop and go to output. Otherwise, set $k = k + 1$ and return to Step 1.
\end{algorithmic}
\Ensure{The approximate solution $x^k$.}
\end{algorithm}

