\Procedure{WeightedMatch}{$R,B$}
\For {$r \in R$}\Comment{All for loop statements run in parallel}
\State $b\gets\mathrm{BreadthFirstSearch}(r,B)$
\State $M\gets M\cup \{r\to b\}$
\EndFor
