\Procedure{BreadthFirstSearch}{$r,B$}
\For{$i=1,...,d$}
\For{$v\in Q_d$, $\|v-r\|_1=i$}
\If{$v\in B$}
\State $B\gets B\setminus{v}$
\State \textbf{return} $v$\Comment{r matches to v}
\EndIf
\EndFor
\EndFor
\EndProcedure
\end{algorithmic}

